test.config:
indexer
{
	mem_limit		= 30M
}

searchd
{

}

source disk
{
	type			= mysql

	sql_query		= select * from test_table
	sql_attr_uint	= gid
}

source klist
{
	type			= mysql

	sql_query		= select * from test_table
	sql_attr_uint	= gid
	sql_query_killlist = select 4
}

index disk
{
	source			= disk
	path			= /disk
}

index disk1 : disk
{
	source			= disk
	path			= /disk1
}

index klist : disk
{
	source = klist
	path = /klist
	killlist_target = disk1:kl
}

index rt
{
	type			= rt
	path			= /rt
	rt_attr_uint = gid
	rt_field = title
}

index rt1 : rt
{
	path			= /rt1
}

test.db_create:
CREATE TABLE test_table
(
	id INTEGER NOT NULL,
	gid INTEGER NOT NULL,
	title VARCHAR(255) NOT NULL
);

queries.sphinxql:

SELECT * FROM rt ORDER BY id ASC;
show index rt status like '%documents';
SELECT * FROM disk ORDER BY id ASC;
show index disk status like '%documents';
ATTACH INDEX disk TO RTINDEX rt;
show index rt status like '%documents';
SELECT * FROM rt ORDER BY id ASC;
SELECT * FROM disk ORDER BY id ASC;
delete from rt where id=2;
show index rt status like '%documents';
select * from rt ORDER BY id ASC;
select count(*) from rt;
delete from rt where id=2;
show index rt status like '%documents';
select * from rt ORDER BY id ASC;
select count(*) from rt;
debug dedup rt 0;
show index rt status like '%documents';
select * from rt ORDER BY id ASC;
select count(*) from rt;
debug compress rt 0 option sync=1;
show index rt status like '%documents';
select * from rt ORDER BY id ASC;
select count(*) from rt;


insert into rt1 (id,title,gid) values (1, 'dupe of doc1', 15), (4, 'It was dupe here', 45);
SELECT * FROM rt1 ORDER BY id ASC;
show index rt1 status like '%documents';
SELECT * FROM disk1 ORDER BY id ASC;
show index disk1 status like '%documents';
ATTACH INDEX disk1 TO RTINDEX rt1;
show index rt1 status like '%documents';
SELECT * FROM rt1 ORDER BY id ASC;
SELECT * FROM disk1 ORDER BY id ASC;
delete from rt1 where id=2;
show index rt1 status like '%documents';
select * from rt1 ORDER BY id ASC;
select count(*) from rt1;
delete from rt1 where id=2;
show index rt1 status like '%documents';
select * from rt1 ORDER BY id ASC;
select count(*) from rt1;
debug dedup rt1 0;
show index rt1 status like '%documents';
select * from rt1 ORDER BY id ASC;
select count(*) from rt1;
debug compress rt1 0 option sync=1;
show index rt1 status like '%documents';
debug compress rt1 1 option sync=1;
show index rt1 status like '%documents';
select * from rt1 ORDER BY id ASC;
select count(*) from rt1;
